const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const content = item.json.content;
  let textContent = '';

  for (const block of content) {
    if (block.type === 'text') {
      textContent += block.text;
    }
  }

  const startIdx = textContent.indexOf('[');
  const endIdx = textContent.lastIndexOf(']');
  if (startIdx === -1 || endIdx === -1 || endIdx <= startIdx) {
    continue;
  }

  let jsonStr = textContent.substring(startIdx, endIdx + 1);
  jsonStr = jsonStr.replace(/[\x00-\x1F\x7F]/g, (ch) => {
    if (ch === '\n' || ch === '\r' || ch === '\t') return ch;
    return ' ';
  });

  let articles;
  try {
    articles = JSON.parse(jsonStr);
  } catch (e) {
    try {
      let fixed = jsonStr;
      if (!fixed.trim().endsWith(']')) fixed += '"}]';
      articles = JSON.parse(fixed);
    } catch (e2) {
      continue;
    }
  }

  const country = $('Set — Liste des pays G20').all()[i];
  const countryCode = country ? country.json.code : 'UNKNOWN';
  const countryName = country ? country.json.name : 'Unknown';

  for (let j = 0; j < articles.length; j++) {
    results.push({
      json: {
        country_code: countryCode,
        country_name: countryName,
        article_index: j,
        ...articles[j]
      }
    });
  }
}

return results;

const items = $input.all();
const parserItems = $('Code — Parser la réponse Claude').all();
const aggregated = {};

for (let i = 0; i < parserItems.length; i++) {
  const prevData = parserItems[i].json;
  const ytData = items[i] ? items[i].json : {};

  let videoId = '';
  let videoTitle = '';
  let videoThumbnail = '';

  if (ytData.items && ytData.items.length > 0 && !ytData.error) {
    videoId = ytData.items[0].id.videoId || '';
    videoTitle = ytData.items[0].snippet.title || '';
    videoThumbnail = ytData.items[0].snippet.thumbnails?.high?.url || '';
  }

  const article = {
    ...prevData,
    youtube_video_id: videoId,
    youtube_video_title: videoTitle,
    youtube_thumbnail: videoThumbnail,
    youtube_embed_url: videoId ? `https://www.youtube.com/embed/${videoId}` : ''
  };

  const code = article.country_code || 'UNKNOWN';
  if (!aggregated[code]) {
    aggregated[code] = [];
  }
  aggregated[code].push(article);
}

return [{ json: { news_data: aggregated, updated_at: new Date().toISOString() } }];
